import React from "react";
import { LineChart, Line, XAxis, YAxis, Tooltip, Legend, ResponsiveContainer } from "recharts";

export default function BusCharts({ buses }) {
  // Count per status
  const data = [
    {
      name: "Running",
      count: buses.filter((b) => b.status === "Running").length,
    },
    {
      name: "Ghost",
      count: buses.filter((b) => b.status === "Ghost").length,
    },
    {
      name: "Anomaly",
      count: buses.filter((b) => b.status === "Anomaly").length,
    },
  ];

  return (
    <div
      style={{
        position: "absolute",
        top: 60,
        left: 50,
        width: 400,
        height: 250,
        background: "rgba(255,255,255,0.95)",
        padding: 10,
        borderRadius: 10,
        boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
        zIndex: 1000,
      }}
    >
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={data}>
          <XAxis dataKey="name" />
          <YAxis />
          <Tooltip />
          <Legend />
          <Line type="monotone" dataKey="count" stroke="#8884d8" />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}
